var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"우… 우우…","JPN":"う、うう……","ENG":"Ughh... Blegh...","TWN":"嗝嗝…嗝…"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"대체 얼마나 먹어댄 거야? 제대로 일어서지도 못하고 있잖아.","JPN":"いったいどんだけ食べたのよ？　まともに立つこともできなくなってるじゃない。","ENG":"How much did you eat? You can't even stand up straight.","TWN":"你到底是吃了多少？吃到連站都站不起來。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"헤헤… 오랜만에 맛있는 게 입에 들어와서, 잔뜩 먹어버렸어요.","JPN":"へへ……久々に口の中に美味しいものが入ってきたので、思わず食べ過ぎちゃいました。","ENG":"Hehe... It's been a long time since I had something so good that I couldn't stop.","TWN":"嘿嘿…好久沒吃到這麼好吃的東西，一時沒節制。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"마지막 요리는 고기만 건져 먹어도 됐잖아. 국물까지 전부 마실 필요는 없었다고.","JPN":"最後の料理は肉だけ食べればよかったでしょ。汁まで飲み干すことはなかったわよ。","ENG":"You could've just eaten the meat in the last dish and not drunk the entire broth.","TWN":"最後那道菜，把肉吃掉就好了，不需要連湯都喝光吧？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그치만… 남기고 싶지 않았는 걸요.","JPN":"でも……一滴も残したくなかったんです。","ENG":"But... I didn't want to leave any behind.","TWN":"可是…我不想浪費。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"따뜻한 식량을 낭비할 수는 없으니까요.","JPN":"温かい食事を無駄にするわけにはいきませんから。","ENG":"Because we can't waste hot food.","TWN":"不能浪費熱騰騰的食物。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh*","TWN":"哀哀…"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐, 주인장도 다 남김 없이 먹은 걸 보고 좋아하긴 했지.","JPN":"まぁ、店長も残さずに食べたことは喜んでくれていたけど。","ENG":"Well, at least the owner looked happy that you ate everything.","TWN":"不過，老闆看到你吃光光應該很開心啦。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그래도 성자가 그렇게 몸을 함부로 쓰지 마.","JPN":"でも聖者なんだから、少しは身体を大切にしなさいよ。","ENG":"But a Helgon shouldn't be so careless with her body.","TWN":"但是，聖者還是不能這樣隨意對待自己的身體。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 튼튼한 몸은 사람들을 구하기 위한 거지. 배가 터지기 직전까지 먹으라고 있는 게 아니니까.","JPN":"この頑丈な身体はみんなを守るためにあるものであって、お腹が張り裂けるほど食べるためにあるもんじゃないんだからね。","ENG":"Your body was made strong to protect the people, not to eat until your stomach is about to explode.","TWN":"你那副健壯的身體是拿來救人的，不是拿來吃到飽的。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"후후… 명심할게요-","JPN":"ふふ……気をつけます～","ENG":"Haha... I'll keep that in mind–","TWN":"呵呵…我會記住的。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"딸꾹-!","JPN":"ひっく！","ENG":"*Hiccup*","TWN":"嗝——！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그거… 맛있어?","JPN":"それ……おいしいの？","ENG":"Was it... good?","TWN":"那個…好喝嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"네? 뭐가요?","JPN":"はい？　何がですか？","ENG":"Hmm? Was what good?","TWN":"嗯？什麼東西？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"좀 전에 마신 포도주 말이야. 그거 맛있었냐고.","JPN":"さっき飲んでいたあれよ、ブドウ酒のことよ。","ENG":"The wine you drank earlier. Was it good?","TWN":"你剛才喝的葡萄酒，好喝嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"앗, 모르가나는 술을 마셔본 적이 없구나?","JPN":"あっ、モルガナはお酒を飲んだことがないんだ？","ENG":"Oh! You've never drunk alcohol before, Morgana?","TWN":"喔～莫甘娜從來沒喝過酒喔？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"아하핫- 역시 애기다, 애기-","JPN":"アハハッーやっぱり子どもなんだね、子ども～","ENG":"Ah hah hah. That just means you're still a wittle baby!","TWN":"哈哈哈…果然是小朋友，小鬼…"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그, 그야 나이가 안 되니까 당연한 거잖아!","JPN":"そ、それはまだ年齢的にダメだから、当然でしょ！","ENG":"I-it's only because I'm not of age yet!","TWN":"那是因為我還沒到可以喝酒的年紀！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이런 시덥잖은 질문, 딱히 할만한 사람도 없었으니까.","JPN":"それに、こんなくだらない質問をする相手も、今までいなかったし。","ENG":"Plus, I don't have anyone else I can ask these stupid questions but you.","TWN":"又沒人可以讓我問這種無聊的問題。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"응- 엄청 달콤하고 사랑스럽고 맛있었어.","JPN":"うーんとね。すごく甘くて、愛しくて、美味しいわよ。","ENG":"Yeah! It's so sweet and lovely!","TWN":"嗝！甜甜的，很好喝喔！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"얼굴이 새빨개. 말투도 평소랑 달라.","JPN":"顔が真っ赤。いつもと話し方も違う。","ENG":"Your face is so red. And you're talking differently.","TWN":"臉這麼紅，說話的語氣也和平時不一樣。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"주인장은 분명 한 잔만 권했는데… 설마 그 정도로도 취하는 건가?","JPN":"店長は一杯しか出してないのに……まさかそれだけで酔っぱらっちゃったの？","ENG":"I'm certain the owner only offered one drink... but was that enough to get you drunk?","TWN":"老闆明明只叫你一杯…這麼容易就喝醉啦？"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린은 분명 저런 포도주쯤 몇 병씩 마셔대도…","JPN":"マーリンはきっとあのブドウ酒なら、何本飲んでも……","ENG":"Merlin can drink bottles of wine before–","TWN":"梅林明明能一口氣喝好幾杯這種葡萄酒…"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"우왓…! 무, 무슨 짓이야! 왜 사람을 멋대로 끌어안고…","JPN":"うわっ……！　な、何やってんの！　なんで人を勝手に抱きかかえて……","ENG":"Whoa...! W-what are you doing?! Why are you all of a sudden hugging–","TWN":"哎呀…！你…你幹嘛！幹嘛突然撲過來…"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"으허엉- 모르가나-!","JPN":"ウホーモルガナー！","ENG":"WAAAAH! MORGANAAAAA!","TWN":"嗚哇——！莫甘娜——！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};